<template>
  <div
    id="chartMapView"
    :style="{ width: cwidth + 'px', height: cheight - 30 + 'px' }"
  ></div>
</template>

<script>
// import yanan from '../assets/common/yanan.json'
// import testData from "@/assets/common/data";

export default {
  name: "echart-map",
  props: {
    mapConfigs: {
      default: function () {
        return [];
      }
    },
    chartHeight: {
      type: Number,
      default: null
    },
    chartLabel: {
      type: Array,
      default: null
    },
    chartWidth: {
      type: Number,
      default: null
    },
    lengendSet: {
      type: String,
      default: null
    }
  },
  computed: {
    chartDatas1 () {
      return this.mapConfigs;
    },
    cwidth () {
      return this.chartWidth;
    },
    cheight () {
      return this.chartHeight;
    }
  },

  data () {
    let _self = this;
    return {
      chartDatas: [],
      option: {
        tooltip: {
          tooltip: "item",
          formatter: function (params) {
            let toolTipData = _self.chartDatas;
            var toolTiphtml = "";
            for (var i = 0; i < toolTipData.length; i++) {
              if (params.name == toolTipData[ i ].name) {
                toolTiphtml += toolTipData[ i ].name + ":<br>";
                for (var j = 0; j < toolTipData[ i ].value.length; j++) {
                  toolTiphtml +=
                    toolTipData[ i ].value[ j ].name +
                    ":" +
                    toolTipData[ i ].value[ j ].value +
                    "<br>";
                }
              }
            }
            return toolTiphtml;
            // return JSON.stringify(params);
          },
          padding: 10,
          enterable: true,
          transitionDuration: 1,
          textStyle: {
            color: "#fff",
            decoration: "none"
          }
        },
        visualMap: {
          min: 0,
          max: 100,
          seriesIndex: 1,
          show: true,
          left: "20%",
          bottom: "10%",
          text: [ "高", "低" ],
          calculable: true,
          textStyle: {
            color: "#fff"
          },
          inRange: {
            color: [ "#38c8ff", "#00467F" ] // 蓝绿
          }
        },
        geo: {
          show: true,
          map: "yanan",
          label: {
            normal: {
              show: true,
              textStyle: {
                color: "#fff",
                fontSize: 16,
                decoration: "none"
              }
            },
            emphasis: {
              show: false
            }
          },
          roam: false,
          itemStyle: {
            normal: {
              areaColor: "#023677",
              borderColor: "#1180c7"
            },
            emphasis: {
              areaColor: "#4499d0"
            }
          }
        },
        series: [
          {
            name: "散点",
            type: "scatter",
            coordinateSystem: "geo",
            data: [],
            symbolSize: 0.1,
            label: {
              normal: {
                formatter: "{b}",
                position: "left",
                show: false,
                textStyle: {
                  color: "#fff",
                  fontSize: 20,
                  decoration: "none"
                }
              },
              emphasis: {
                show: false
              }
            },
            itemStyle: {
              normal: {
                color: "#05C3F9"
              }
            }
          },
          {
            type: "map",
            confine: true,
            map: "yanan",
            // name: "医疗",
            // trigger: "item",
            geoIndex: 0,
            // aspectScale: 1, //长宽比
            showLegendSymbol: false, // 存在legend时显示
            label: {
              normal: {
                show: false
              },
              emphasis: {
                show: false,
                textStyle: {
                  color: "#fff"
                }
              }
            },
            roam: true,
            animation: false,
            data: []
          },
          {
            name: "点",
            type: "scatter",
            tooltip: {
              trigger: "none"
            },
            coordinateSystem: "geo",
            // symbol: 'pin', //气泡
            symbol:
              "image://data:image/png;base64,", //气泡
            symbolOffset: [ 0, "-50%" ],
            symbolSize: null,
            label: {
              // formatter: '{b}: {@[3]}',
              normal: {
                formatter: "{@[2]}",
                // formatter: function(c) {

                //   return JSON.stringify(c.value[2].value);
                // },
                show: true,
                textStyle: {
                  color: "#fff",
                  fontSize: 12
                }
              }
            },
            itemStyle: {
              normal: {
                borderColor: "#F62157",
                color: "rgb(128, 128, 128)", //标志颜色
                backgroundColor: "#F62157"
              }
            },
            zlevel: 9,
            data: []
          }
        ]
      }
    };
  },
  methods: {

    setEchartMapData (e, d) {

      return
      let self = this;
      let mapName = "panjin";
      let max = 13000,
        min = 4800; // todo
      let maxSize4Pin = 60,
        minSize4Pin = 10;
      let geoCoordMap = {};
      let mapFeatures = this.$echarts.getMap(mapName).geoJson.features;
      mapFeatures.forEach(function (v) {
        // 地区名称
        let name = v.properties.name;
        // 地区经纬度
        geoCoordMap[ name ] = v.properties.center;
      });
      let LabelMax = [];

      if (d.length > 0) {
        for (let a = 0; a < d.length; a++) {
          let Sum = [];
          for (let n = 0; n < d[ a ].value.length; n++) {
            Sum.push(d[ a ].value[ n ].value);
          }
          let SumMax = Sum.reduce(function (prev, cur) {
            return prev + cur;
          }, 0);
          LabelMax.push(SumMax);
          let LabelMaxNum = Math.max(...Array.from(new Set(LabelMax)));
          LabelMaxNum = parseInt(LabelMaxNum / 10) * 11;
          e.visualMap.max = LabelMaxNum;
        }
      }

      let ops = e;
      if (self.lengendSet === "是") {
        ops.visualMap.show = true;
      } else {
        ops.visualMap.show = false;
      }
      ops[ "grid" ] = {
        width: this.cwidth,
        height: this.cheight
      };
      let ser = ops.series;

      let convertData = function (data, t) {
        var res = [];
        for (var i = 0; i < data.length; i++) {
          let SunArr = [];
          var geoCoord = geoCoordMap[ data[ i ].name ];
          let v = data[ i ].value;

          let max = 0;
          for (let j = 0; j < v.length; j++) {
            SunArr.push(v[ j ].value);
          }
          let sum = SunArr.reduce(function (prev, cur) {
            return prev + cur;
          }, 0);
          if (t === "scatter") {
            if (geoCoord) {
              res.push({
                name: data[ i ].name,
                value: geoCoord.concat(sum)
              });
            }
          } else {
            res.push({
              name: data[ i ].name,
              value: sum
            });
          }
        }

        return res;
      };

      ser = ser.map(item => {
        if (item.type === "scatter" && item.name !== "散点") {
          item.symbolSize = function (val) {
            if (val[ 2 ] >= 0 && val[ 2 ] < 10) {
              max = 4800;
              min = 100;
            } else if (val[ 2 ] >= 10 && val[ 2 ] < 100) {
              max = 400;
              min = 100;
            } else if (val[ 2 ] >= 100 && val[ 2 ] < 1000) {
              max = 2000;
              min = 100;
            } else if (val[ 2 ] >= 1000 && val[ 2 ] < 10000) {
              if (val[ 2 ] >= 1000 && val[ 2 ] < 3000) {
                max = 900;
                min = 120;
                maxSize4Pin = 25;
              } else if (val[ 2 ] >= 5000) {
                max = 8500;
                min = 900;
                maxSize4Pin = 80;
                minSize4Pin = 10;
              } else if (val[ 2 ] >= 3000 && val[ 2 ] < 5000) {
                max = 1000;
                min = 120;
                maxSize4Pin = 20;
              }
            } else if (val[ 2 ] >= 10000 && val[ 2 ] < 100000) {
              max = 13000;
              min = 280;
              maxSize4Pin = 60;
            }
            var a = (maxSize4Pin - minSize4Pin) / (max - min);
            var b = minSize4Pin - a * min;
            b = maxSize4Pin - a * max;
            return a * val[ 2 ] + b;
          };
          item.data = convertData(d, item.type);
        } else {
          item.data = convertData(d, item.type);
        }
        return item;
      });
      let chartMapView = this.$echarts.init(
        document.getElementById("chartMapView")
      ); // 获取图标dom,装载echart实例
      chartMapView.setOption(ops);
    }
  },

  mounted () {
    let chartMapView = this.$echarts.init(
      document.getElementById("chartMapView")
    ); // 获取图标dom,装载echart实例
    chartMapView.resize();
    this.setEchartMapData(this.option, this.chartDatas);
  },
  watch: {
    mapConfigs: {
      handler: function (newValue, oldValue) {
        this.chartDatas = newValue;
        this.setEchartMapData(this.option, this.chartDatas);
      },
      deep: true //对象内部的属性监听，即深度监听
    },
    chartWidth: {
      handler: function (newValue, oldValue) {
        let chartMapView = this.$echarts.init(
          document.getElementById("chartMapView")
        ); // 获取图标dom,装载echart实例
        chartMapView.resize();
      }
    },
    chartHeight: {
      handler: function (newValue, oldValue) {
        let chartMapView = this.$echarts.init(
          document.getElementById("chartMapView")
        ); // 获取图标dom,装载echart实例
        chartMapView.resize();
      }
    }
  }
};
</script>

<style lang="scss" scoped>
.bx-chart-views {
  width: 100%;
  height: 100%;
  .chart-main {
    .chart-title {
      text-align: left;
      font-size: 2rem;
      border-left: 2px solid #fff;
      text-indent: 0.2rem;
    }
  }
}
</style>